function LBattleViewEffect:InitView(idx,parentTrans,effId,pos,dir,startTime,playTime,dissipateTime,isLongCache,resType)
    self._index = idx
    self._parentTrans = parentTrans

    if pos then
        pos = pos:Clone()
    else
        pos = Vector3(0,0,0)
    end
    self._pos = pos

    self._dir = dir

    self._effectName = effId

    self._startTime = self._viewMgr:GetTime() + startTime

    self._playTime = self._startTime + playTime

    self._dissipateTime = self._playTime + dissipateTime

    self._effectType = resType or LBattleViewEffect.EFFECT

    if isLongCache then
        self._isLongCache = isLongCache
    end
end


