function LBattleViewEffect:_InitWenzi(tran,logStr)
    local skillId = self._skillId
    if not skillId and skillId < 1 then
        table.insert(logStr,"找不到 skillId")
        return
    end
    local skillRef = GameTable.SnakeSkillRef[skillId]
    if not skillRef then
        table.insert(logStr,"skillRef不存在，skillId = " .. skillId)
        return
    end

    local effType = self._effType or 0
    if effType == LSkillEffConst.PLAY_EFF_TREASURE_ICON then
        local wenziTxtTrans = FindChild(tran,"wenziTxt")
        if not IsValid(wenziTxtTrans) then
            wenziTxtTrans = FindChild(tran,"guadian/wenziTxt")
        end
        if IsValid(wenziTxtTrans) then
            local nameIcon1 = skillRef.nameIcon1
            if nameIcon1 and nameIcon1 > 0 then
                ---@type V_DraconicRef
                local ref = self._viewMgr:GetDataMgr():GetDraconicRefBySkillId(skillId)
                if ref then
                    local quality = ref.quality
                    if quality and quality > 0 then
                        local colorStr = nil
                        if quality == 4 then
                            colorStr = "de42ff|f39dff"
                        elseif quality == 5 then
                            colorStr = "ff7e00|ff9a5c"
                        elseif quality == 6 then
                            colorStr = "ff2828|ff786b"
                        elseif quality == 7 then
                            colorStr = "ffe958|fffde8"
                        end
                        local alignment
                        local changeScale = self._changeScale
                        if changeScale then
                            local x = changeScale.x
                            local curTxtScale = wenziTxtTrans.localScale
                            local isRight = x < 1
                            alignment = isRight and 4 or 6
                            local newX = isRight and -curTxtScale.x or curTxtScale.x
                            wenziTxtTrans.localScale = Vector3(newX,curTxtScale.y,curTxtScale.z)
                        end
                        LxUiHelper.SetTextMeshProColorGradientStr(wenziTxtTrans,colorStr)
                        local testMeshPro = LxUiHelper.GetXTextMeshProCtrl(wenziTxtTrans)
                        if testMeshPro then
                            testMeshPro.text = I18nText(skillRef.name)
                            if alignment and alignment > 0 then
                                local alignmentEnum = LxUiHelper.GetTMPAlignment(alignment)
                                if alignmentEnum then
                                    testMeshPro.alignment = alignmentEnum
                                end
                            end
                        end
                        return
                    end
                end
            end
        end
    end

    local nameTran = FindChild(tran,"wenzi")
    if not IsValid(nameTran) then
        nameTran = FindChild(tran,"guadian/wenzi")
    end
    if IsValid(nameTran) then
        if not string.isempty(skillRef.nameIcon) then
            local nameIconPath = skillRef.nameIcon
            ShowObject(nameTran.gameObject,false)
            local iconImg = nameTran:GetComponent(typeOfSpriteRenderer)
            if iconImg then
                local spite = self:GetSprite(iconImg)
                spite:SetLoadedCallback(function ()
                    ShowObject(nameTran.gameObject,true)
                    if LxLngHelper:IsForeignVersion() then
                        if iconImg and iconImg.sprite then
                            local width = iconImg.sprite.rect.width
                            local offset = -width/200
                            nameTran.localPosition = Vector3.new(offset,0,0)
                        end
                        --nameTran.localPosition = Vector3.new(-1.2,0,0)
                    end
                end)
                self:SetImage(iconImg,nameIconPath,true)
            end
        else
            table.insert(logStr,"skillRef.nameIcon 为空，skillId = " .. skillId)
        end
    else
        table.insert(logStr,"没有找到路径(wenzi 或者 guadian/wenzi)：" .. tran.name)
    end
end


