function LBattleViewEffect:PlayEffect()
    local state = self._effectState
    self._isPlaying = true
    if state == LBattleViewEffect.STATE_NONE then
        self:LoadEffectImpl(self._index,self._parentTrans,self._effectName,self._effectType)
    elseif state == LBattleViewEffect.STATE_LOADED then
        self:StartPlay()
    end
end




function LBattleViewEffect:CalcCurvePos(traceType,tarPos,bulletTarPos)
    if(traceType == 1) then
        return self:CalcCurvePosOne(tarPos,bulletTarPos)
    elseif(traceType == 2) then
        return self:CalcCurvePosTwo(tarPos,bulletTarPos)
    end
    return tarPos,bulletTarPos
end

function LBattleViewEffect:CalcCurvePosOne(tarPos,bulletTarPos)
    local topPosX = Mathf.Lerp(tarPos.x , bulletTarPos.x,  2 / 3)
    local topPosY = Mathf.Lerp(tarPos.y , bulletTarPos.y,  0.5)
    local offectY = Vector3.Distance(tarPos, bulletTarPos)
    local topPos = Vector3(topPosX,topPosY + offectY,0)
    return topPos,bulletTarPos
end

function LBattleViewEffect:CalcCurvePosTwo(tarPos,bulletTarPos)
    local topPosX = Mathf.Lerp(tarPos.x , bulletTarPos.x,  1 / 2)
    local topPosY = Mathf.Lerp(tarPos.y , bulletTarPos.y,  0.5)
    local offectY
    local isUp = self._bulletIndex % 2 == 1
    if isUp then
        offectY = math.random(0,15) * 0.1
    else
        offectY = math.random(-15,0) * 0.1
    end

    local topPos = Vector3(topPosX,topPosY + offectY,0)

    return topPos,bulletTarPos
end

function LBattleViewEffect:SetPosition(pos)
    if not self._loadDp then
        return
    end
    if not self._loadDp:IsDpValid() then
        return
    end
    local dpTrans = self._loadDp:GetDpTrans()
    dpTrans.position = Vector3(pos.x,pos.y,pos.y * 0.01)
end

function LBattleViewEffect:Dispose()
    if self._isDisposed then
        return
    end

    if self._loadDp then
        self._loadDp:Dispose()
        self._loadDp = nil
    end

    LxNodeBase.Dispose(self)
end

function LBattleViewEffect:IsDisposed()
    return self._isDisposed
end
