function LBattleViewEffect:OnUpdate(time, deltaTime)
    if self._isDisposed then return false end

    if not self._isPlaying then
        if self._startTime <= time then
            self:PlayEffect()
        end
    else
        if not self._isPersistence then
            if self._dissipateTime < time  then
                if self._onEndCall then
                    self._onEndCall()
                    self._onEndCall = nil
                end
                return false
            end
        end
    end
    return true
end

