function LBattleViewEffect:SetVisible(isVisible)
    if self._loadDp then
        self._loadDp:SetVisible(isVisible)
    end
end

function LBattleViewEffect:ResetToPreloaded()
    self._isPlaying = false
    self._effectState = LBattleViewEffect.STATE_LOADED
    local dp = self._loadDp
    dp:SetVisible(false)
    if self._effectType == LBattleViewEffect.SPINE then
        return
    end

    if not self._isInit then
        return
    end

    dp:ClearOldPlayState()
end



