---整理战斗特效加载接口
function LBattleViewEffect:LoadEffectImpl(idx,root,resName,resType,endFunc)
    resType = resType or 1

    if self._effectState > LBattleViewEffect.STATE_NONE then
        return
    end

    self._effectState = LBattleViewEffect.STATE_LOADING

    ---@type LxBaseDp
    local dp
    local isSuc
    if resType == LBattleViewEffect.SPINE then
        dp = LxSpineDp:new()
    else
        dp = LxEffectDp:new()
    end

    self._loadDp = dp

    isSuc = dp:InitDp(resName, root)
    dp:SetLoadedCallback(function()
        self:OnCheckNeedAddBone(resType)
        self:OnEffectLoadSuc()
        if endFunc then
            endFunc(idx)
        end
    end)
    dp:SetLoadFailCallback(function()
        self._effectState = LBattleViewEffect.STATE_NONE
        if endFunc then
            endFunc(idx)
        end
    end)
    dp:Load()

    return isSuc
end

function LBattleViewEffect:OnCheckNeedAddBone(resType)
    if resType == LBattleViewEffect.SPINE then return end
    if self._createType == LBattleViewEffect.NORMAL then
        self:CheckNormalIsNeedAddBone()
    elseif self._createType == LBattleViewEffect.PRELOAD then
        self:CheckPreloadIsNeedAddBone()
    end
end

function LBattleViewEffect:CheckNormalIsNeedAddBone()
    if not self._loadDp then return end

    if not self._targetObj or string.isempty(self._boneName) then return end

    local spineDp = self._targetObj:GetDisplayObj()
    if not spineDp then return end

    self:InternalInitBoneFollower(spineDp,self._boneName)
end

---@param spineDp LxSpineDp
---@param boneName string
function LBattleViewEffect:InternalInitBoneFollower(spineDp,boneName)
    if self:IsDisposed() then return end
    if not self._loadDp or self._loadDp:IsDisposed() then return end
    local effectTrans = self._loadDp:GetDpTrans()
    if not effectTrans then return end
    local boneFollower = effectTrans:GetComponent(typeOfBoneFollower)
    if not boneFollower then
        boneFollower = effectTrans.gameObject:AddComponent(typeOfBoneFollower)
    end
    local skeletonAni = spineDp:GetSkeletonAnimation()
    if skeletonAni then
        boneFollower.SkeletonRenderer = skeletonAni
        boneFollower:SetBone(boneName)
    end
end

function LBattleViewEffect:CheckPreloadIsNeedAddBone()
    if not self._loadDp then return end

    if not self._targetObj or string.isempty(self._boneName) then return end

    local spineDp = self._targetObj:GetDisplayObj()
    if not spineDp then return end

    ---@type LxEffectDp
    local loadDp = self._loadDp
    loadDp:InternalInitBoneFollower(spineDp,self._boneName)
end

